// ApiService.java
import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class ApiService {
    private static final String BASE_URL_DEV = "https://dev.api.example.com/";
    private static final String BASE_URL_STAGING = "https://staging.api.example.com/";
    private static final String BASE_URL_PROD = "https://api.example.com/";

    public enum Environment {
        DEVELOPMENT,
        STAGING,
        PRODUCTION
    }

    private static Retrofit retrofit;

    public static UserApi getUserService(Environment environment) {
        if (retrofit == null) {
            OkHttpClient client = new OkHttpClient.Builder().build();

            String baseUrl;
            switch (environment) {
                case DEVELOPMENT:
                    baseUrl = BASE_URL_DEV;
                    break;
                case STAGING:
                    baseUrl = BASE_URL_STAGING;
                    break;
                default:
                    baseUrl = BASE_URL_PROD;
            }

            retrofit = new Retrofit.Builder()
                    .baseUrl(baseUrl)
                    .addConverterFactory(GsonConverterFactory.create())
                    .client(client)
                    .build();
        }
        return retrofit.create(UserApi.class);
    }
}

